    for (let i = 0; i < n; i++) {
        // The score is the count of numbers to the right (j > i)
        // that have different parity than nums[i].

        // Get the counts of odds and evens strictly to the right of i.
        // Since we calculated right_odd[i] and right_even[i] based on indices > i,
        // we can use these directly.
        const odds_right = right_odd[i];
        const evens_right = right_even[i];

        let score = 0;
        const isOdd = nums[i] % 2 !== 0;

        if (isOdd) {
            // If nums[i] is odd, we count the even numbers to the right.
            score = evens_right;
        } else {
            // If nums[i] is even, we count the odd numbers to the right.
            score = odds_right;
        }

        answer[i] = score;
    }

    return answer;
}

